package pages;import org.openqa.selenium.By;import org.openqa.selenium.WebDriver;public class LoginPage {    private WebDriver driver;    private By username = By.name("username");    private By password = By.name("password");    private By loginButton = By.cssSelector("button[type='submit']");    public LoginPage(WebDriver driver) {        this.driver = driver;    }    public void abrirLogin() {        driver.get("https://ernest.xo.je/index.php?route=auth/login");    }    public void iniciarSesion(String usuario, String clave) {        driver.findElement(username).sendKeys(usuario);        driver.findElement(password).sendKeys(clave);        driver.findElement(loginButton).click();    }}